```jsx
function App() {
  const [cartItems, setCartItems] = useState([]);
  // La logique panier est définie ici
  return (
    &lt;Layout&gt;
      &lt;Header&gt;
        &lt;CartIcon cartItems={cartItems} setCartItems={setCartItems} /&gt;
      &lt;/Header&gt;
      &lt;MainContent&gt;
        &lt;ProductList cartItems={cartItems} setCartItems={setCartItems} /&gt;
      &lt;/MainContent&gt;
    &lt;/Layout&gt;
  );
}

function Header({ children }) {
  return (
    &lt;header&gt;
      &lt;Logo /&gt;
      {children}
    &lt;/header&gt;
  );
}
```
Header ne reçoit plus les props du panier. C'est App qui décide de passer directement CartIcon à l'intérieur de Header via la prop `children`.

