```jsx
function Dashboard() {
  const userId = "user-123";
  return (
    &lt;Sidebar&gt;
      &lt;UserMenu&gt;
        &lt;ProfileLink userId={userId} /&gt;
      &lt;/UserMenu&gt;
    &lt;/Sidebar&gt;
  );
}

function Sidebar({ children }) {
  return &lt;div className="sidebar"&gt;{children}&lt;/div&gt;;
}

function UserMenu({ children }) {
  return &lt;div className="user-menu"&gt;{children}&lt;/div&gt;;
}

function ProfileLink({ userId }) {
  return &lt;a href={`/profile/${userId}`}&gt;Mon profil&lt;/a&gt;;
}
```
Le composant Dashboard compose explicitement la structure : ProfileLink est passé comme enfant à UserMenu, qui est lui-même enfant de Sidebar. Plus aucun composant intermédiaire n'a besoin de connaître userId.
